import json

from botocore.exceptions import ClientError


def detect_malformed_action_response(trace):
    for step in trace.get('trace', {}).get('steps', []):
        if step.get('type') == 'agent_step':
            for action in step.get('actionGroups', []):
                if 'failure' in action and 'parsing' in str(action.get('failure', {})):
                    return {
                        'issue': 'MALFORMED_ACTION_RESPONSE',
                        'stepId': step.get('stepId'),
                        'error': action['failure'],
                        'actionGroup': action.get('actionGroup')
                    }
    return None

def detect_kb_retrieval_failure(response):
    retrievals = response.get('output', {}).get('retrievalMetadata', [])
    poor_retrievals = [r for r in retrievals if r.get('score', 0) < 0.7]

    if len(poor_retrievals) > len(retrievals) * 0.8:
        return {
            'issue': 'POOR_KB_RETRIEVAL',
            'retrievalCount': len(retrievals),
            'poorRetrievals': len(poor_retrievals),
            'avgScore': sum(r.get('score', 0) for r in retrievals) / len(retrievals)
        }
    return None

export function detectGuardrailViolation(response: any): any | null {
  const assessments = response.output?.contentBlocks?.[0]?.guardrail?.contentAssessment || [];

  const domainPolicies = {
    'PII': ['SSN', 'credit card'],
    'toxic': ['hate speech'],
    'restricted_topics': ['weapons', 'drugs']
  };

  for (const assessment of assessments) {
    if (assessment.assessmentResult === 'ALLOWED') {
      for (const [policy, keywords] of Object.entries(domainPolicies)) {
        for (const keyword of keywords) {
          if (response.input?.text?.toLowerCase().includes(keyword)) {
            return {
              issue: 'DOMAIN_GUARDRAIL_FAILURE',
              policy,
              keyword,
              assessment
            };
          }
        }
      }
    }
  }
  return null;
}

