import boto3

kb_client = boto3.client('bedrock-agent-runtime')

def invoke_agent_with_enhanced_kb(agent_id, session_id, input_text):
    # Enable hybrid retrieval with multiple chunk sizes
    response = kb_client.invoke_agent(
        agentId=agent_id,
        agentAliasId='latest',
        sessionId=session_id,
        inputText=input_text,
        enableTrace=True,
        sessionState={
            'retrievalConfiguration': {
                'vectorSearchConfiguration': {
                    'numberOfResults': 10,
                    'overrideSearchType': 'HYBRID'
                },
                'knowledgeBaseConfiguration': {
                    'generationConfiguration': {
                        'promptTemplate': {
                            'textPromptTemplate': 'Use these documents: $search_results$\nAnswer: '
                        }
                    }
                }
            }
        }
    )
    return response

export async function createDomainGuardrails(guardrailId: string) {
  const bedrock = new BedrockAgent();

  await bedrock.createGuardrail({
    name: guardrailId,
    description: 'Domain-specific enterprise guardrails',
    contentPolicyConfig: {
      filtersConfig: {
        type: 'ContentFilter',
        inputStrength: 'HIGH',
        outputStrength: 'HIGH',
        filters: [
          {
            type: 'PiiEntityFilter',
            entityType: 'STANDARD',
            action: 'BLOCK'
          },
          {
            type: 'WordPolicyFilter',
            wordsConfig: {
              words: ['weapons', 'drugs', 'hacking'],
              action: 'BLOCK'
            }
          }
        ]
      }
    }
  });
}
